// ─── Helpers ──────────────────────────────────────────────────────────────────
const SK = "idx-b-v11";
const GIST_URL = "https://gist.githubusercontent.com/dglsgh/a89227769eb88c2b6490515bdab96295/raw/idx_briefing.json";
const todayKey = () => new Date().toISOString().slice(0, 10);
const fmtShort = d => new Date(d).toLocaleDateString("en-GB", { day: "numeric", month: "short" });
const fmtFull  = d => new Date(d).toLocaleDateString("en-GB", { weekday: "long", day: "numeric", month: "long", year: "numeric" });
const fmtTime  = d => new Date(d).toLocaleTimeString("en-GB", { hour: "2-digit", minute: "2-digit" });
const fmtShares = n => n >= 1e9 ? (n/1e9).toFixed(2)+"B" : n >= 1e6 ? (n/1e6).toFixed(1)+"M" : n >= 1e3 ? (n/1e3).toFixed(0)+"K" : n.toString();

// ─── Gist → internal format bridge ────────────────────────────────────────────
// generate_briefing.py stores bullet arrays as newline-joined strings;
// the JSX expects real arrays + a structured trivia object.
function parseGistBriefing(raw) {
  const toArr = s => (s || "").split("\n").map(l => l.replace(/^[•\-\*]\s*/, "").trim()).filter(Boolean);
  const trivRaw = (raw.trivia || "").split("\n");
  const term    = (trivRaw[0] || "").replace(/\*\*/g, "");
  const body    = trivRaw.slice(1).join(" ").trim();
  const m       = body.match(/^(.+?[.!?])\s+(.+)$/s);
  const [line1, line2] = m ? [m[1], m[2]] : [body, ""];
  return {
    date:        raw.date,
    macroDate:   raw.macroDate || raw.date,
    generatedAt: raw.generatedAt,
    headline:    raw.headline,
    sentiment:   raw.sentiment,
    sections: {
      macro:   toArr(raw.macro),
      sectors: toArr(raw.sectors),
      tickers: toArr(raw.tickers),
      discord: toArr(raw.discord),
      trivia:  { term, line1, line2 },
    },
  };
}

// ─── Sector classifier ────────────────────────────────────────────────────────
function deriveSector(name, code) {
  const n = name.toUpperCase();
  if (/BANK|FINANSIA|FINANCE|KREDIT|DANAMON|MANDIRI|BNI|BRI|BCA|MEGA|NIAGA|PERMATA|PANIN|ARTO|JAGO/.test(n)) return "Finance";
  if (/ASURANSI|INSURANCE|JIWA|TAKAFUL|SOMPO|ALLIANZ/.test(n)) return "Insurance";
  if (/TELKO|TELEKOMUNIKASI|INTERNET|INDOSAT|XL AXIATA|TOWER/.test(n)) return "Telco";
  if (/MEDIA|TELEVISI|FILM|CINEMA|MNCN|EMTK|VISI|BALI TV|MAHAKA/.test(n)) return "Media";
  if (/TAMBANG|MINING|COAL|BATU BARA|NIKEL|NICKEL|TINS|TIMAH|GOLD|EMAS|ANTAM|BAUXITE/.test(n)) return "Mining";
  if (/MINYAK|OIL|GAS|PETRO|ENERGY|ENERGI|BRENT|EL NINO|PGAS|GEOTHERMAL/.test(n)) return "Energy";
  if (/SAWIT|PALM|AGRO|PLANTATION|KEBUN|PERKEBUNAN|AGRI|CPO|TEH/.test(n)) return "Agri";
  if (/PROPERTI|PROPERTY|REAL ESTAT|REAL ESTATE|REALTY|LAND|TANAH|SUMMARECON|CIPUTRA|PAKUWON/.test(n)) return "Property";
  if (/KONSTRUKSI|CONSTRUCTION|WIKA|WSKT|WASKITA|ADHI|NRCA/.test(n)) return "Construction";
  if (/FARMASI|PHARMA|HEALTH|KESEHATAN|HOSPITAL|SAKIT|MEDIKA|KIMIA FARMA|KALBE|SIDO/.test(n)) return "Health";
  if (/RETAIL|RITEL|MINIMARKET|SUPERMARKET|SWALAYAN|RAMAYANA|MATAHARI|ALFAMART|INDOMARET/.test(n)) return "Retail";
  if (/TEKNOLOGI|TECHNOLOGY|DIGITAL|SOFTWARE|IT|GOJEK|TOKOPEDIA|BUKALAPAK|GOTO|BUKA/.test(n)) return "Tech";
  if (/SEMEN|CEMENT|BAJA|STEEL|IRON|KACA|GLASS|PLASTIK|PLASTIC|KERAMIK|CERAMIC/.test(n)) return "Industrial";
  if (/MAKANAN|FOOD|MINUMAN|BEVERAGE|MINUM|SNACK|BISCUIT/.test(n)) return "Consumer";
  if (/ROKOK|TOBACCO|SAMPOERNA|GUDANG GARAM|DJARUM|HM/.test(n)) return "Consumer";
  if (/TRANSPOR|TRANSPORT|LOGISTIK|LOGISTICS|SHIPPING|PELAYARAN|PENERBANGAN|AIRLINES|GARUDA/.test(n)) return "Transport";
  if (/JALAN TOL|TOLL|INFRASTRUKTUR|INFRASTRUCTURE|PELABUHAN|PORT|AIRPORT|BANDARA/.test(n)) return "Infrastructure";
  if (/PUPUK|FERTILIZER|KIMIA|CHEMICAL|PETROKIMIA/.test(n)) return "Chemical";
  if (/TEKSTIL|TEXTILE|GARMEN|GARMENT|APPAREL|FASHION/.test(n)) return "Textile";
  if (/HOTEL|WISATA|TOURISM|RESORT|PARIWISATA|RESTORAN|RESTAURANT/.test(n)) return "Tourism";
  return "Other";
}

// ─── Process KSEI data ────────────────────────────────────────────────────────
const KSEI = KSEI_RAW.map(item => {
  const localPct   = item.h.filter(x => x[2] === "L").reduce((a, x) => a + x[3], 0);
  const foreignPct = item.h.filter(x => x[2] === "F").reduce((a, x) => a + x[3], 0);
  const hhi        = Math.round(item.h.reduce((a, x) => a + x[3] * x[3], 0));
  const sector     = deriveSector(item.n, item.c);
  return { c: item.c, n: item.n, h: item.h, localPct, foreignPct, hhi, count: item.h.length, sector };
});

const ALL_SECTORS = ["All", ...Array.from(new Set(KSEI.map(k => k.sector))).sort()];

