// ─── Shared style helpers ─────────────────────────────────────────────────────
const tierColor = p => p >= 50 ? "#d05050" : p >= 20 ? "#c49a30" : p >= 5 ? "#6090d8" : "#505068";
const tierLabel = p => p >= 50 ? "Controlling" : p >= 20 ? "Significant" : p >= 5 ? "Notable" : "Minor";
const hhiColor  = h => h > 2500 ? "#d05050" : h > 1500 ? "#c49a30" : "#3ea46e";
const hhiLabel  = h => h > 2500 ? "High" : h > 1500 ? "Moderate" : "Low";

const sectorHue = s => ({
  Finance:"#4a7cc0", Insurance:"#5060a0", Telco:"#5a6abf", Media:"#8050a0",
  Industrial:"#506050", Energy:"#a06030", Mining:"#806040", Consumer:"#4a7870",
  Tech:"#3a6080", Construction:"#606060", Infrastructure:"#505870", Retail:"#706050",
  Agri:"#407050", Property:"#805040", Health:"#407068", Transport:"#505878",
  Chemical:"#5a5040", Textile:"#705858", Tourism:"#5a6040", Other:"#484858"
}[s] || "#484858");

const colorArrows = str =>
  str.replace(/\*\*(.*?)\*\*/g, '<strong style="color:#d8d8e6;font-weight:500">$1</strong>')
     .replace(/↑/g, '<span style="color:#3ea46e">↑</span>')
     .replace(/↓/g, '<span style="color:#d05050">↓</span>')
     .replace(/→/g, '<span style="color:#c49a30">→</span>');

// ─── Market Update components ──────────────────────────────────────────────────
function BulletLine({ text, isTldr, twoLine }) {
  const clean = text.replace(/^[•\-\*]\s*/, "");
  if (twoLine && clean.includes("|")) {
    const [hdr, exp] = clean.split("|").map(s => s.trim());
    return (
      <div style={{ display:"flex", gap:10, alignItems:"flex-start" }}>
        <span style={{ color:"#2a2a36", fontSize:10, flexShrink:0, marginTop:3 }}>—</span>
        <div>
          <div style={{ color:"#c0c0d0", fontSize:13, fontWeight:500, lineHeight:1.45 }} dangerouslySetInnerHTML={{ __html: colorArrows(hdr) }} />
          <div style={{ color:"#5a5a70", fontSize:12, lineHeight:1.45, marginTop:1 }} dangerouslySetInnerHTML={{ __html: colorArrows(exp) }} />
        </div>
      </div>
    );
  }
  return (
    <div style={{ display:"flex", gap:10, alignItems:"flex-start" }}>
      <span style={{ color:"#2a2a36", fontSize:10, flexShrink:0, marginTop:3 }}>—</span>
      <span style={{ color: isTldr ? "#b8b8c8" : "#8a8a9c", fontSize:13, lineHeight:1.5 }} dangerouslySetInnerHTML={{ __html: colorArrows(clean) }} />
    </div>
  );
}

function BriefSection({ s, lines, open, onToggle, onCopy, copied, macroDate, briefingDate }) {
  const isTldr  = s.id === "discord";
  const twoLine = s.id === "sectors" || s.id === "tickers";
  const showStaleDate = s.id === "macro" && macroDate && briefingDate && macroDate !== briefingDate;
  return (
    <div style={{ border:"1px solid rgba(255,255,255,0.07)", borderRadius:10, background:"rgba(255,255,255,0.01)", overflow:"hidden", display:"flex", flexDirection:"column" }}>
      <button onClick={onToggle} style={{ width:"100%", display:"flex", alignItems:"center", gap:10, padding:"13px 16px", background:"transparent", border:"none", cursor:"pointer", borderBottom: open ? "1px solid rgba(255,255,255,0.05)" : "none" }}>
        <span style={{ fontSize:12 }}>{s.icon}</span>
        <span style={{ flex:1, color:"#c8c8d8", fontSize:13, fontWeight:600, textAlign:"left", letterSpacing:"-0.01em" }}>{s.label}</span>
        {showStaleDate && (
          <span style={{ fontSize:10, color:"#505068", background:"rgba(255,255,255,0.03)", border:"1px solid rgba(255,255,255,0.06)", borderRadius:3, padding:"1px 6px", marginRight:4 }}>
            last updated {fmtShort(macroDate)}
          </span>
        )}
        {isTldr && (
          <button onClick={e => { e.stopPropagation(); onCopy(); }}
            style={{ fontSize:10, color: copied ? "#3ea46e" : "#7a5cc0", background: copied ? "rgba(62,164,110,0.1)" : "rgba(122,92,192,0.1)", padding:"2px 8px", borderRadius:3, border:"none", cursor:"pointer", marginRight:4 }}>
            {copied ? "✓ Copied" : "copy"}
          </button>
        )}
        <span style={{ color:"#2a2a3a", fontSize:10 }}>{open ? "▲" : "▼"}</span>
      </button>
      {open && (
        <div style={{ padding:"14px 16px", display:"flex", flexDirection:"column", gap: twoLine ? 10 : 8, flex:1 }}>
          {lines.map((line, i) => <BulletLine key={i} text={line} isTldr={isTldr} twoLine={twoLine} />)}
        </div>
      )}
    </div>
  );
}

