// ─── IHSG Heatmap ──────────────────────────────────────────────────────────────
function IHSGHeatmapSection({ heatmap }) {
  // Group KSEI by sector, count tickers — visual placeholder until price data arrives
  const sectors = useMemo(() => {
    const counts = {};
    for (const item of KSEI) {
      counts[item.sector] = (counts[item.sector] || 0) + 1;
    }
    return Object.entries(counts).sort((a,b) => b[1]-a[1]).slice(0,14);
  }, []);

  if (!heatmap || heatmap.length === 0) return (
    <div style={{ border:"1px solid rgba(255,255,255,0.07)", borderRadius:10, background:"rgba(255,255,255,0.01)", overflow:"hidden" }}>
      <div style={{ display:"flex", alignItems:"center", gap:8, padding:"13px 16px", borderBottom:"1px solid rgba(255,255,255,0.05)" }}>
        <span style={{ fontSize:12 }}>🗺</span>
        <span style={{ flex:1, color:"#c8c8d8", fontSize:13, fontWeight:600, letterSpacing:"-0.01em" }}>IHSG Sector Heatmap</span>
        <span style={{ fontSize:10, color:"#383850", background:"rgba(255,255,255,0.02)", border:"1px solid rgba(255,255,255,0.05)", borderRadius:3, padding:"1px 7px" }}>awaiting price data</span>
      </div>
      <div style={{ padding:"14px 16px" }}>
        <div style={{ display:"flex", flexWrap:"wrap", gap:6 }}>
          {sectors.map(([s, count]) => (
            <div key={s} style={{ padding:"8px 12px", borderRadius:7, background:sectorHue(s)+"18", border:`1px solid ${sectorHue(s)}30`, minWidth:80, textAlign:"center" }}>
              <div style={{ fontSize:11, fontWeight:600, color:sectorHue(s)+"dd" }}>{s}</div>
              <div style={{ fontSize:10, color:"#404058", marginTop:2 }}>{count} tickers</div>
              <div style={{ fontSize:10, color:"#2a2a40", marginTop:2 }}>— %</div>
            </div>
          ))}
        </div>
        <div style={{ marginTop:10, fontSize:10, color:"#2e2e48" }}>
          Add <code style={{ color:"#404060", background:"rgba(255,255,255,0.04)", padding:"1px 5px", borderRadius:3 }}>heatmap</code> array to Gist JSON to show daily % changes · generate_briefing.py fetches .JK prices via yfinance
        </div>
      </div>
    </div>
  );
}

function DockItem({ b, isCurrent, offset, onClick }) {
  const scale   = Math.max(0.70, 1 - Math.abs(offset) * 0.12);
  const opacity = Math.max(0.18, 1 - Math.abs(offset) * 0.28);
  const sc = (SENT[b.sentiment] || SENT.neutral).color;
  return (
    <button onClick={onClick} style={{ background:"transparent", border:"none", cursor:"pointer", padding:"3px 0", display:"flex", justifyContent:"flex-end", width:"100%", transform:`scale(${scale})`, opacity, transition:"all 0.2s ease", outline:"none", transformOrigin:"right center" }}>
      <div style={{ padding:"5px 12px", borderRadius:6, background: isCurrent ? "rgba(255,255,255,0.07)" : "transparent", border: isCurrent ? "1px solid rgba(255,255,255,0.1)" : "1px solid transparent", display:"flex", alignItems:"center", gap:6 }}>
        <span style={{ width:5, height:5, borderRadius:"50%", background:sc, flexShrink:0 }} />
        <span style={{ color: isCurrent ? "#e0e0ea" : "#505060", fontSize:11, fontWeight: isCurrent ? 600 : 400, whiteSpace:"nowrap" }}>
          {b.date === todayKey() ? "Today" : fmtShort(b.generatedAt)}
        </span>
      </div>
    </button>
  );
}

function MarketUpdatePage() {
  const [briefings, setBriefings] = useState([]);
  const [selIdx, setSelIdx]       = useState(0);
  const [open, setOpen]           = useState({ macro:true, sectors:true, tickers:true, discord:true });
  const [copied, setCopied]       = useState(false);
  const ts = useMemo(() => new Date().toISOString(), []);
  const selected = briefings[selIdx] ?? null;
  const sent = SENT[selected?.sentiment] || SENT.neutral;

  useEffect(() => {
    (async () => {
      // ── Always ensure HISTORY entries are present ────────────────────────
      const withHistory = (list) => {
        let out = [...list];
        for (const h of HISTORY) {
          if (!out.some(b => b.date === h.date)) out = [...out, h];
        }
        out.sort((a, b) => b.date.localeCompare(a.date));
        return out;
      };

      try {
        const raw  = await window.storage?.get(SK);
        const list = raw ? JSON.parse(raw.value) : [];

        // ── Try live Gist fetch ──────────────────────────────────────────────
        let gist = null;
        if (GIST_URL) {
          try {
            const res = await fetch(GIST_URL + "?t=" + Date.now());
            if (res.ok) gist = parseGistBriefing(await res.json());
          } catch { /* network unavailable – fall through to seed */ }
        }

        // ── Merge: Gist replaces same-date entry; seed fills gap if needed ──
        const seed   = makeSeed(ts);
        let   merged = gist ? list.filter(b => b.date !== gist.date) : [...list];
        if (gist)                                    merged = [gist, ...merged];
        else if (!merged.some(b => b.date === seed.date)) merged = [seed, ...merged];

        const final = withHistory(merged);
        setBriefings(final);
        try { await window.storage?.set(SK, JSON.stringify(final)); } catch {}
      } catch { setBriefings(withHistory([makeSeed(ts)])); }
    })();
  }, []);

  useEffect(() => {
    const h = e => {
      if (e.key === "ArrowUp")   setSelIdx(i => Math.max(0, i - 1));
      if (e.key === "ArrowDown") setSelIdx(i => Math.min(briefings.length - 1, i + 1));
    };
    window.addEventListener("keydown", h);
    return () => window.removeEventListener("keydown", h);
  }, [briefings.length]);

  const copyDiscord = () => {
    if (!selected) return;
    navigator.clipboard.writeText((selected.sections.discord || []).join("\n"));
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const dockItems = briefings.map((b, i) => ({ b, i, offset: i - selIdx })).filter(x => Math.abs(x.offset) <= 3);
  const trivia = selected?.sections?.trivia;

  const [headMain, headSub] = selected?.headline?.includes(" — ")
    ? selected.headline.split(" — ").map(s => s.trim())
    : [selected?.headline || "", ""];

  return (
    <div style={{ flex:1, display:"flex", overflow:"hidden" }}>
      {briefings.length > 0 && (
        <div className="mu-dock" style={{ width:100, display:"flex", flexDirection:"column", justifyContent:"center", alignItems:"flex-end", gap:2, paddingLeft:12, flexShrink:0 }}>
          {dockItems.map(({ b, i, offset }) => <DockItem key={b.date} b={b} isCurrent={i===selIdx} offset={offset} onClick={() => setSelIdx(i)} />)}
          {briefings.length > 1 && <div style={{ marginTop:8, color:"#1e1e28", fontSize:10, textAlign:"right", paddingRight:12 }}>↑↓ keys</div>}
        </div>
      )}
      <div style={{ flex:1, display:"flex", flexDirection:"column", overflow:"hidden" }}>
        <div style={{ flex:1, overflowY:"auto", display:"flex", justifyContent:"center" }}>
          {selected ? (
            <div className="mu-body" style={{ width:"100%", maxWidth:1100, padding:"80px 40px 120px" }}>

              {/* ── Header ── */}
              <div style={{ marginBottom:32 }}>
                <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:14 }}>
                  <div style={{ color:"#444460", fontSize:11, fontWeight:500, letterSpacing:"0.06em", textTransform:"uppercase" }}>
                    {fmtFull(selected.generatedAt)} · {fmtTime(selected.generatedAt)}
                  </div>
                  <span style={{ fontSize:11, fontWeight:600, color:sent.color, background:sent.color+"18", padding:"2px 9px", borderRadius:4, letterSpacing:"0.02em" }}>{sent.label}</span>
                </div>
                <h1 style={{ margin:0, fontSize:40, fontWeight:700, color:"#f0f0fa", letterSpacing:"-0.04em", lineHeight:1.1 }}>{headMain}</h1>
                {headSub && <p style={{ margin:"10px 0 0", fontSize:22, fontWeight:500, color:"#50506a", letterSpacing:"-0.02em", lineHeight:1.3 }}>{headSub}</p>}
              </div>

              {/* ── 2-column section grid ── */}
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:10 }}>
                {SECTS.map(s => (
                  <BriefSection key={s.id} s={s} lines={selected.sections[s.id]||[]} open={open[s.id]}
                    onToggle={() => setOpen(p => ({...p, [s.id]:!p[s.id]}))}
                    onCopy={copyDiscord} copied={copied}
                    macroDate={selected.macroDate} briefingDate={selected.date} />
                ))}
              </div>

              {/* ── Full-width extra sections ── */}
              <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
                <ForeignFlowSection />
                <DividendCalendarSection dividends={selected.dividends} />
                <IHSGHeatmapSection heatmap={selected.heatmap} />
              </div>

            </div>
          ) : <span style={{ color:"#2a2a34", fontSize:13, marginTop:120 }}>Loading…</span>}
        </div>
        {trivia && (
          <div className="mu-trivia" style={{ flexShrink:0, borderTop:"1px solid rgba(255,255,255,0.05)", background:"#09090c", padding:"10px 32px 13px", textAlign:"center" }}>
            <span style={{ color:"#2e2e3c", fontSize:10, fontWeight:600, letterSpacing:"0.08em", textTransform:"uppercase", marginRight:6 }}>🎓 Term of the Day</span>
            <strong style={{ color:"#6a6a88", fontSize:12 }}>{trivia.term}</strong><br />
            <span style={{ color:"#48485e", fontSize:12, lineHeight:1.7 }}>{trivia.line1}</span><br />
            <span style={{ color:"#48485e", fontSize:12, lineHeight:1.7 }}>{trivia.line2}</span>
          </div>
        )}
      </div>
    </div>
  );
}

// ─── Ownership Database components ────────────────────────────────────────────
function TypeBadge({ t }) {
  const map = { CP:"#3060a0", ID:"#306040", MF:"#806030", IS:"#504060", GO:"#603030", IB:"#305060", SC:"#404040", PF:"#405060", FD:"#305048", OT:"#404040" };
  const col = map[t] || "#404040";
  return <span style={{ fontSize:10, padding:"1px 5px", borderRadius:3, background:col+"44", color:col+"ee", fontWeight:600, letterSpacing:"0.04em", border:`1px solid ${col}55` }}>{t||"—"}</span>;
}
function LFBadge({ f }) {
  const isL = f === "L";
  return <span style={{ fontSize:10, padding:"1px 6px", borderRadius:3, background: isL ? "rgba(62,164,110,0.12)" : "rgba(96,144,216,0.12)", color: isL ? "#3ea46e" : "#6090d8", fontWeight:600, border:`1px solid ${isL?"#3ea46e33":"#6090d833"}` }}>{isL ? "Local" : "Foreign"}</span>;
}
function OwnerBar({ local, foreign }) {
  const other = Math.max(0, 100 - local - foreign);
  return (
    <div style={{ height:3, borderRadius:2, overflow:"hidden", background:"#1a1a24", display:"flex", marginTop:6 }}>
      <div style={{ width:`${local}%`, background:"#3ea46e" }} />
      <div style={{ width:`${foreign}%`, background:"#6090d8" }} />
      <div style={{ width:`${other}%`, background:"#2a2a38" }} />
    </div>
  );
}

