// ─── Shared type constants (used by TickerNodeGraph) ─────────────────────────────
const TYPE_COLORS = {
  CP:"#3478c8", ID:"#38a870", MF:"#d4882a", IS:"#7060b8",
  GO:"#c84848", IB:"#28909a", SC:"#707070", PF:"#506088",
  FD:"#388878", OT:"#606060"
};
const TYPE_LABELS = {
  CP:"Corporate", ID:"Individual", MF:"Mutual Fund", IS:"Institutional",
  GO:"Govt", IB:"Inv. Bank", SC:"Securities", PF:"Pension Fund",
  FD:"Fund", OT:"Other"
};

// ─── Ticker Node Graph (pure SVG radial layout — no external deps) ─────────────
function TickerNodeGraph({ item, onInvestorSearch }) {
  const [tooltip, setTooltip] = useState(null);
  const [hovered, setHovered] = useState(null);

  const W = 640, H = 360, cx = W / 2, cy = H / 2;
  const n = item.h.length;
  // Spread nodes on a circle; more nodes → larger radius
  const radius = Math.min(cx - 50, cy - 50, 60 + n * 13);
  const nodeR  = p => Math.max(8, Math.min(22, p * 0.85 + 6));

  const nodes = item.h.map((h, i) => {
    const angle = (i / n) * 2 * Math.PI - Math.PI / 2;
    return {
      id: `h${i}`,
      x: cx + radius * Math.cos(angle),
      y: cy + radius * Math.sin(angle),
      label: h[0].replace(/^PT /i,"").replace(/ TBK$/i,"").replace(/ Tbk$/i,"").substring(0, 20),
      full:   h[0],
      type:   h[1],
      origin: h[2],
      pct:    h[3],
    };
  });

  const shownTypes = [...new Set(item.h.map(h => h[1]))].filter(t => TYPE_COLORS[t]);

  return (
    <div style={{ position:"relative", width:"100%", marginTop:4 }}>
      <svg viewBox={`0 0 ${W} ${H}`} style={{ width:"100%", display:"block" }}>
        {/* Spoke lines */}
        {nodes.map(nd => (
          <line key={nd.id}
            x1={cx} y1={cy} x2={nd.x} y2={nd.y}
            stroke={TYPE_COLORS[nd.type] || "#404060"}
            strokeOpacity={hovered === nd.id ? 0.55 : 0.22}
            strokeWidth={Math.max(1, nd.pct * 0.13)}
          />
        ))}
        {/* % label on spoke midpoint */}
        {nodes.map(nd => (
          <text key={`lbl-${nd.id}`}
            x={(cx + nd.x) / 2} y={(cy + nd.y) / 2 - 4}
            textAnchor="middle" fontSize={7.5} fill="#363650">
            {nd.pct.toFixed(1)}%
          </text>
        ))}
        {/* Center node */}
        <circle cx={cx} cy={cy} r={32} fill="#eeeef6" />
        <text x={cx} y={cy} textAnchor="middle" dy="0.35em"
          fontSize={11} fontWeight={700} fill="#09090c">{item.c}</text>
        {/* Holder nodes */}
        {nodes.map(nd => {
          const r = nodeR(nd.pct);
          const col = TYPE_COLORS[nd.type] || "#505060";
          return (
            <g key={nd.id} transform={`translate(${nd.x},${nd.y})`}
              style={{ cursor:"pointer" }}
              onClick={() => onInvestorSearch && onInvestorSearch(nd.full)}
              onMouseEnter={e => { setHovered(nd.id); setTooltip({ x:e.clientX, y:e.clientY, node:nd }); }}
              onMouseMove={e => setTooltip(t => t ? { ...t, x:e.clientX, y:e.clientY } : null)}
              onMouseLeave={() => { setHovered(null); setTooltip(null); }}>
              <circle r={r}
                fill={col + "22"}
                stroke={col}
                strokeWidth={hovered === nd.id ? 2 : 1.2}
                strokeOpacity={hovered === nd.id ? 0.9 : 0.65} />
              <text textAnchor="middle" dy="-0.15em"
                fontSize={7.5} fontWeight={500} fill="#b0b0c8">{nd.label}</text>
              <text textAnchor="middle" dy="1.1em"
                fontSize={8} fontWeight={600} fill={col}>{nd.pct.toFixed(1)}%</text>
            </g>
          );
        })}
      </svg>

      {/* Legend */}
      <div style={{ display:"flex", gap:5, flexWrap:"wrap", marginTop:4 }}>
        {shownTypes.map(t => (
          <span key={t} style={{ fontSize:9, padding:"1px 6px", borderRadius:3,
            background:(TYPE_COLORS[t])+"22", color:TYPE_COLORS[t],
            fontWeight:600, border:`1px solid ${TYPE_COLORS[t]}44` }}>
            {TYPE_LABELS[t] || t}
          </span>
        ))}
        <span style={{ fontSize:9, color:"#363650", marginLeft:4 }}>hover · click to search investor</span>
      </div>

      {/* Tooltip */}
      {tooltip && (
        <div style={{ position:"fixed", left:tooltip.x+12, top:tooltip.y-10,
          background:"#131318", border:"1px solid rgba(255,255,255,0.1)",
          borderRadius:8, padding:"8px 12px", pointerEvents:"none", zIndex:200,
          fontSize:11, color:"#c0c0d0", maxWidth:210 }}>
          <div style={{ fontWeight:600, marginBottom:3, color:"#e0e0f0", lineHeight:1.3 }}>
            {tooltip.node.full.substring(0, 38)}
          </div>
          <div style={{ color:tierColor(tooltip.node.pct), fontWeight:600 }}>
            {tooltip.node.pct.toFixed(2)}% · {tierLabel(tooltip.node.pct)}
          </div>
          <div style={{ color:TYPE_COLORS[tooltip.node.type]||"#606080", marginTop:2 }}>
            {TYPE_LABELS[tooltip.node.type]||tooltip.node.type} · {tooltip.node.origin==="L"?"Local":"Foreign"}
          </div>
        </div>
      )}
    </div>
  );
}


function OwnershipPage() {
  const [query, setQuery]     = useState("");
  const [sector, setSector]   = useState("All");
  const [detail, setDetail]   = useState(null);
  const [sortBy, setSortBy]   = useState("code"); // code | hhi | float | foreign

  const q = query.trim().toLowerCase();

  const investorHits = useMemo(() => {
    if (q.length < 2) return [];
    const results = [];
    KSEI.forEach(item => {
      item.h.forEach(h => {
        if (h[0].toLowerCase().includes(q)) results.push({ item, holder: h });
      });
    });
    return results.sort((a, b) => b.holder[3] - a.holder[3]).slice(0, 100);
  }, [q]);

  const tickerHits = useMemo(() => {
    const list = KSEI.filter(item => {
      const matchQ = !q || item.c.toLowerCase().includes(q) || item.n.toLowerCase().includes(q);
      const matchS = sector === "All" || item.sector === sector;
      return matchQ && matchS;
    });
    return list.sort((a, b) => {
      if (sortBy === "hhi")     return b.hhi - a.hhi;
      if (sortBy === "foreign") return b.foreignPct - a.foreignPct;
      if (sortBy === "float")   return (a.localPct + a.foreignPct) - (b.localPct + b.foreignPct);
      return a.c.localeCompare(b.c);
    });
  }, [q, sector, sortBy]);

  const showInvestorTable = q.length >= 2 && investorHits.length > 0;
  const isInvestorOnlySearch = showInvestorTable && tickerHits.length === 0;

  if (detail) {
    return (
      <div style={{ flex:1, overflowY:"auto", display:"flex", justifyContent:"center", paddingTop:80 }}>
        <TickerDetail item={detail} onBack={() => setDetail(null)} onInvestorSearch={name => { setQuery(name); setDetail(null); }} />
      </div>
    );
  }

  return (
    <div style={{ flex:1, overflowY:"auto", display:"flex", justifyContent:"center" }}>
      <div className="ow-body" style={{ width:"100%", maxWidth:"none", padding:"80px 32px 80px" }}>

              {/* Search bar */}
              <div style={{ marginBottom:16 }}>
                <div style={{ fontSize:11, color:"#404058", letterSpacing:"0.05em", textTransform:"uppercase", marginBottom:6 }}>
                  KSEI · 27 Feb 2026 · {KSEI.length} tickers · 7,257 records
                </div>
                <div style={{ position:"relative" }}>
                  <span style={{ position:"absolute", left:12, top:"50%", transform:"translateY(-50%)", color:"#404058", fontSize:14, pointerEvents:"none" }}>🔍</span>
                  <input value={query} onChange={e => { setQuery(e.target.value); setDetail(null); }}
                    placeholder="Search ticker, company name, or investor…"
                    style={{ width:"100%", background:"rgba(255,255,255,0.04)", border:"1px solid rgba(255,255,255,0.08)", borderRadius:8, padding:"10px 36px 10px 38px", color:"#c8c8d8", fontSize:13, outline:"none", boxSizing:"border-box" }} />
                  {query && <button onClick={() => setQuery("")} style={{ position:"absolute", right:10, top:"50%", transform:"translateY(-50%)", background:"none", border:"none", color:"#505068", cursor:"pointer", fontSize:13 }}>✕</button>}
                </div>
              </div>

              {/* Filters */}
              {!q && (
                <div style={{ marginBottom:14 }}>
                  <div style={{ display:"flex", gap:5, flexWrap:"wrap", marginBottom:8 }}>
                    {ALL_SECTORS.map(s => (
                      <button key={s} onClick={() => setSector(s)} style={{ fontSize:11, padding:"3px 9px", borderRadius:5, cursor:"pointer", fontWeight: sector===s?600:400, background: sector===s ? sectorHue(s==="All"?"Finance":s)+"33" : "rgba(255,255,255,0.03)", color: sector===s?"#d0d0e4":"#5a5a70", border:`1px solid ${sector===s?"rgba(255,255,255,0.1)":"rgba(255,255,255,0.05)"}` }}>
                        {s}
                      </button>
                    ))}
                  </div>
                  <div style={{ display:"flex", gap:5 }}>
                    <span style={{ fontSize:11, color:"#404058", marginRight:4 }}>Sort:</span>
                    {[["code","A–Z"],["hhi","Most Concentrated"],["foreign","Most Foreign"],["float","Lowest Float"]].map(([k,l]) => (
                      <button key={k} onClick={() => setSortBy(k)} style={{ fontSize:11, padding:"3px 9px", borderRadius:5, cursor:"pointer", fontWeight: sortBy===k?600:400, background: sortBy===k?"rgba(255,255,255,0.08)":"rgba(255,255,255,0.02)", color: sortBy===k?"#c8c8d8":"#505068", border:"1px solid rgba(255,255,255,0.06)" }}>
                        {l}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {/* Investor search results */}
              {showInvestorTable && (
                <div style={{ marginBottom:24 }}>
                  <div style={{ fontSize:11, color:"#6090d8", textTransform:"uppercase", letterSpacing:"0.05em", marginBottom:10 }}>
                    {investorHits.length} position{investorHits.length!==1?"s":""} · investor match for "{query}"
                    {investorHits.length===100&&<span style={{ color:"#404058" }}> (showing top 100)</span>}
                  </div>
                  <div style={{ borderTop:"1px solid rgba(255,255,255,0.06)" }}>
                    <div className="inv-grid" style={{ display:"grid", gridTemplateColumns:"70px 1fr 50px 80px 80px 80px", gap:8, padding:"8px 0", borderBottom:"1px solid rgba(255,255,255,0.04)" }}>
                      {[{l:"Code"},{l:"Investor"},{l:"Type",cn:"col-type"},{l:"Origin",cn:"col-origin"},{l:"Ownership"},{l:"Tier",cn:"col-inv-tier"}].map(({l,cn}) => (
                        <div key={l} className={cn} style={{ fontSize:10, color:"#383848", textTransform:"uppercase", letterSpacing:"0.05em" }}>{l}</div>
                      ))}
                    </div>
                    {investorHits.map((m, i) => (
                      <div key={i} className="inv-grid" onClick={() => setDetail(m.item)}
                        style={{ display:"grid", gridTemplateColumns:"70px 1fr 50px 80px 80px 80px", gap:8, padding:"8px 0", borderBottom:"1px solid rgba(255,255,255,0.03)", alignItems:"center", cursor:"pointer" }}
                        onMouseEnter={e => e.currentTarget.style.background="rgba(255,255,255,0.02)"}
                        onMouseLeave={e => e.currentTarget.style.background="transparent"}
                      >
                        <div style={{ fontSize:13, fontWeight:700, color:"#6090d8" }}>{m.item.c}</div>
                        <div style={{ fontSize:11, color:"#8a8a9c", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{m.holder[0]}</div>
                        <div className="col-type"><TypeBadge t={m.holder[1]} /></div>
                        <div className="col-origin"><LFBadge f={m.holder[2]} /></div>
                        <div style={{ fontSize:13, fontWeight:600, color:tierColor(m.holder[3]) }}>{m.holder[3].toFixed(2)}%</div>
                        <div className="col-inv-tier" style={{ fontSize:10, color:tierColor(m.holder[3]) }}>{tierLabel(m.holder[3])}</div>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {/* Ticker grid */}
              {!isInvestorOnlySearch && tickerHits.length > 0 && (
                <>
                  {showInvestorTable && <div style={{ fontSize:11, color:"#505068", textTransform:"uppercase", letterSpacing:"0.05em", marginBottom:10 }}>Tickers</div>}
                  <div style={{ marginBottom:8, fontSize:11, color:"#383848" }}>
                    {tickerHits.length === KSEI.length ? `All ${KSEI.length} tickers` : `${tickerHits.length} ticker${tickerHits.length!==1?"s":""}`}
                  </div>
                  <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill, minmax(185px, 1fr))", gap:8 }}>
                    {tickerHits.map(item => <TickerCard key={item.c} item={item} onClick={() => setDetail(item)} />)}
                  </div>
                </>
              )}

              {!isInvestorOnlySearch && tickerHits.length === 0 && q && (
                <div style={{ color:"#383848", fontSize:13, textAlign:"center", paddingTop:40 }}>No tickers match "{query}"</div>
              )}
            </div>
          </div>
  );
}

// ─── App shell ─────────────────────────────────────────────────────────────────
function App() {
  const [page, setPage] = useState("briefing");
  const [dark, setDark] = useState(() => window.matchMedia?.("(prefers-color-scheme: dark)").matches ?? true);
  useEffect(() => {
    const mq = window.matchMedia?.("(prefers-color-scheme: dark)");
    if (!mq) return;
    const handler = e => setDark(e.matches);
    mq.addEventListener("change", handler);
    return () => mq.removeEventListener("change", handler);
  }, []);
  return (
    <div style={{ height:"100vh", background:"#09090c", color:"#d0d0de", fontFamily:"-apple-system, BlinkMacSystemFont, 'SF Pro Text', 'Segoe UI', sans-serif", fontSize:13, display:"flex", flexDirection:"column", overflow:"hidden", position:"relative", filter: dark ? "none" : "invert(1) hue-rotate(180deg)" }}>
      <div style={{ position:"absolute", top:14, left:20, zIndex:20, display:"flex", gap:2 }}>
        {[["briefing","Market Update"],["ownership","Ownership Database"]].map(([id, label]) => (
          <button key={id} onClick={() => setPage(id)} style={{ fontSize:12, padding:"4px 11px", borderRadius:6, border:"none", cursor:"pointer", fontWeight: page===id?600:400, background: page===id?"rgba(255,255,255,0.08)":"transparent", color: page===id?"#e0e0ea":"#404058", transition:"all 0.15s" }}>
            {label}
          </button>
        ))}
      </div>
      <button onClick={() => setDark(d => !d)} style={{ position:"absolute", top:12, right:14, zIndex:20, background:"rgba(255,255,255,0.04)", border:"1px solid rgba(255,255,255,0.08)", borderRadius:6, padding:"3px 10px", cursor:"pointer", fontSize:14, color:"#606072", lineHeight:1 }} title={dark ? "Switch to light mode" : "Switch to dark mode"}>
        {dark ? "☀" : "☾"}
      </button>
      {page === "briefing"  && <MarketUpdatePage />}
      {page === "ownership" && <OwnershipPage />}
      <style>{`
        * { box-sizing:border-box; margin:0; padding:0; }
        ::-webkit-scrollbar { width:4px; }
        ::-webkit-scrollbar-thumb { background:rgba(255,255,255,0.06); border-radius:2px; }
        input::placeholder { color:#404058; }
        input:focus { border-color:rgba(255,255,255,0.14)!important; }
        @media (max-width:640px) {
          .mu-dock   { width:60px!important; padding-left:4px!important; }
          .mu-body   { padding:70px 14px 120px!important; }
          .mu-grid   { grid-template-columns:1fr!important; }
          .mu-trivia { padding:10px 14px 16px!important; }
          .ow-body   { padding:64px 12px 80px!important; }
          .holder-grid { grid-template-columns:1fr 65px 65px!important; }
          .inv-grid    { grid-template-columns:50px 1fr 70px!important; }
          .col-type, .col-origin, .col-inv-tier { display:none!important; }
        }
      `}</style>
    </div>
  );
}
ReactDOM.createRoot(document.getElementById('root')).render(React.createElement(App));
